3345 /// arrays accessed are fixed-size arrays. Return true if delinearization was
3346 /// successful.
3347 bool DependenceInfo::tryDelinearizeFixedSize(
3348     Instruction *Src, Instruction *Dst, const SCEV *SrcAccessFn,
3349     const SCEV *DstAccessFn, SmallVectorImpl<const SCEV *> &SrcSubscripts,
