3354     const SCEVUnknown *DstBase =
3355         dyn_cast<SCEVUnknown>(SE->getPointerBase(DstAccessFn));
3356     assert(SrcBase && DstBase && SrcBase == DstBase &&
3357            "expected src and dst scev unknowns to be equal");
3358   });
3359 
3360   const SCEV *ElemSize = SE->getElementSize(Src);
3361   assert(ElemSize == SE->getElementSize(Dst) && "Different element sizes");
3362   SmallVector<const SCEV *, 4> SrcSizes, DstSizes;
3363   if (!delinearizeFixedSizeArray(*SE, SE->removePointerBase(SrcAccessFn),
3364                                  SrcSubscripts, SrcSizes, ElemSize) ||
3365       !delinearizeFixedSizeArray(*SE, SE->removePointerBase(DstAccessFn),
3366                                  DstSubscripts, DstSizes, ElemSize))
3367     return false;
3368 
3369   // Check that the two size arrays are non-empty and equal in length and
3370   // value.  SCEV expressions are uniqued, so we can compare pointers.
3371   if (SrcSizes.size() != DstSizes.size() ||
3372       !std::equal(SrcSizes.begin(), SrcSizes.end(), DstSizes.begin())) {
3373     SrcSubscripts.clear();
3374     DstSubscripts.clear();
3375     return false;
3376   }
3377 
3378   assert(SrcSubscripts.size() == DstSubscripts.size() &&
3379          "Expected equal number of entries in the list of SrcSubscripts and "
3380          "DstSubscripts.");
3381 
3382   // In general we cannot safely assume that the subscripts recovered from GEPs
3383   // are in the range of values defined for their corresponding array
3384   // dimensions. For example some C language usage/interpretation make it
3385   // impossible to verify this at compile-time. As such we can only delinearize
3386   // iff the subscripts are positive and are less than the range of the
3387   // dimension.
3388   if (!DisableDelinearizationChecks) {
3389     if (!validateDelinearizationResult(*SE, SrcSizes, SrcSubscripts) ||
3390         !validateDelinearizationResult(*SE, DstSizes, DstSubscripts)) {
3391       SrcSubscripts.clear();
3392       DstSubscripts.clear();
3393       return false;
3394     }
3395   }
