3475 bool DependenceInfo::invalidate(Function &F, const PreservedAnalyses &PA,
3476                                 FunctionAnalysisManager::Invalidator &Inv) {
3477   // Check if the analysis itself has been invalidated.
3478   auto PAC = PA.getChecker<DependenceAnalysis>();
3479   if (!PAC.preserved() && !PAC.preservedSet<AllAnalysesOn<Function>>())
3480     return true;
3481 
3482   // Check transitive dependencies.
3483   return Inv.invalidate<AAManager>(F, PA) ||
3484          Inv.invalidate<ScalarEvolutionAnalysis>(F, PA) ||
3485          Inv.invalidate<LoopAnalysis>(F, PA);
