 789 /// We only care about an affine AddRec at the moment. For an affine AddRec,
 790 /// the monotonicity can be inferred from its nowrap property. For example, let
 791 /// X and Y be loop-invariant, and assume Y is non-negative. An AddRec
 792 /// {X,+.Y}<nsw> implies:
 793 ///
 794 ///   X <=s (X + Y) <=s ((X + Y) + Y) <=s ...
 795 ///
 796 /// Thus, we can conclude that the AddRec is monotonically increasing with
 797 /// respect to the associated loop in a signed sense. The similar reasoning
 798 /// applies when Y is non-positive, leading to a monotonically decreasing
 799 /// AddRec.
 800 SCEVMonotonicity
 801 SCEVMonotonicityChecker::visitAddRecExpr(const SCEVAddRecExpr *Expr) {
 802   if (!Expr->isAffine() || !Expr->hasNoSignedWrap())
 803     return createUnknown(Expr);
 804 
 805   const SCEV *Start = Expr->getStart();
 806   const SCEV *Step = Expr->getStepRecurrence(*SE);
 807 
 808   SCEVMonotonicity StartMon = visit(Start);
 809   if (StartMon.isUnknown())
 810     return StartMon;
 811 
 812   if (!isLoopInvariant(Step))
 813     return createUnknown(Expr);
 814 
 815   return SCEVMonotonicity(SCEVMonotonicityType::MultivariateSignedMonotonic);
 816 }
