 895 // Returns NoAlias/MayAliass/MustAlias for two memory locations based upon their
 896 // underlaying objects. If LocA and LocB are known to not alias (for any reason:
 897 // tbaa, non-overlapping regions etc), then it is known there is no dependecy.
 898 // Otherwise the underlying objects are checked to see if they point to
 899 // different identifiable objects.
 900 static AliasResult underlyingObjectsAlias(AAResults *AA, const DataLayout &DL,
 901                                           const MemoryLocation &LocA,
 902                                           const MemoryLocation &LocB) {
 903   // Check the original locations (minus size) for noalias, which can happen for
 904   // tbaa, incompatible underlying object locations, etc.
 905   MemoryLocation LocAS =
 906       MemoryLocation::getBeforeOrAfter(LocA.Ptr, LocA.AATags);
 907   MemoryLocation LocBS =
 908       MemoryLocation::getBeforeOrAfter(LocB.Ptr, LocB.AATags);
 909   BatchAAResults BAA(*AA);
 910   BAA.enableCrossIterationMode();
 911 
 912   if (BAA.isNoAlias(LocAS, LocBS))
 913     return AliasResult::NoAlias;
 914 
 915   // Check the underlying objects are the same
 916   const Value *AObj = getUnderlyingObject(LocA.Ptr);
 917   const Value *BObj = getUnderlyingObject(LocB.Ptr);
 918 
 919   // If the underlying objects are the same, they must alias
 920   if (AObj == BObj)
 921     return AliasResult::MustAlias;
 922 
 923   // We may have hit the recursion limit for underlying objects, or have
 924   // underlying objects where we don't know they will alias.
 925   if (!isIdentifiedObject(AObj) || !isIdentifiedObject(BObj))
 926     return AliasResult::MayAlias;
 927 
 928   // Otherwise we know the objects are different and both identified objects so
 929   // must not alias.
 930   return AliasResult::NoAlias;
 931 }
