 943 // Returns true if two loops have the Same iteration Space and Depth. To be
 944 // more specific, two loops have SameSD if they are in the same nesting
 945 // depth and have the same backedge count. SameSD stands for Same iteration
 946 // Space and Depth.
 947 bool DependenceInfo::haveSameSD(const Loop *SrcLoop,
 948                                 const Loop *DstLoop) const {
 949   if (SrcLoop == DstLoop)
 950     return true;
 951 
 952   if (SrcLoop->getLoopDepth() != DstLoop->getLoopDepth())
 953     return false;
 954 
 955   if (!SrcLoop || !SrcLoop->getLoopLatch() || !DstLoop ||
 956       !DstLoop->getLoopLatch())
 957     return false;
 958 
 959   const SCEV *SrcUB = nullptr, *DstUP = nullptr;
 960   if (SE->hasLoopInvariantBackedgeTakenCount(SrcLoop))
 961     SrcUB = SE->getBackedgeTakenCount(SrcLoop);
 962   if (SE->hasLoopInvariantBackedgeTakenCount(DstLoop))
 963     DstUP = SE->getBackedgeTakenCount(DstLoop);
 964 
 965   if (SrcUB != nullptr && DstUP != nullptr) {
 966     Type *WiderType = SE->getWiderType(SrcUB->getType(), DstUP->getType());
 967     SrcUB = SE->getNoopOrZeroExtend(SrcUB, WiderType);
 968     DstUP = SE->getNoopOrZeroExtend(DstUP, WiderType);
 969 
 970     if (SE->isKnownPredicate(ICmpInst::ICMP_EQ, SrcUB, DstUP))
 971       return true;
 972   }
 973 
 974   return false;
 975 }
