642 // FIXME: in some cases the meaning of a negative direction vector
643 // may not be straightforward, e.g.,
644 // for (int i = 0; i < 32; ++i) {
645 //   Src:    A[i] = ...;
646 //   Dst:    use(A[31 - i]);
647 // }
648 // The dependency is
649 //   flow { Src[i] -> Dst[31 - i] : when i >= 16 } and
650 //   anti { Dst[i] -> Src[31 - i] : when i < 16 },
651 // -- hence a [<>].
652 // As long as a dependence result contains '>' ('<>', '<=>', "*"), it
653 // means that a reversed/normalized dependence needs to be considered
654 // as well. Nevertheless, current isDirectionNegative() only returns
655 // true with a '>' or '>=' dependency for ease of canonicalizing the
656 // dependency vector, since the reverse of '<>', '<=>' and "*" is itself.
657 bool FullDependence::isDirectionNegative() const {
658   for (unsigned Level = 1; Level <= Levels; ++Level) {
659     unsigned char Direction = DV[Level - 1].Direction;
660     if (Direction == Dependence::DVEntry::EQ)
661       continue;
662     if (Direction == Dependence::DVEntry::GT ||
663         Direction == Dependence::DVEntry::GE)
664       return true;
665     return false;
666   }
667   return false;
668 }
