670 bool FullDependence::normalize(ScalarEvolution *SE) {
671   if (!isDirectionNegative())
672     return false;
673 
674   LLVM_DEBUG(dbgs() << "Before normalizing negative direction vectors:\n";
675              dump(dbgs()););
676   std::swap(Src, Dst);
677   for (unsigned Level = 1; Level <= Levels; ++Level) {
678     unsigned char Direction = DV[Level - 1].Direction;
679     // Reverse the direction vector, this means LT becomes GT
680     // and GT becomes LT.
681     unsigned char RevDirection = Direction & Dependence::DVEntry::EQ;
682     if (Direction & Dependence::DVEntry::LT)
683       RevDirection |= Dependence::DVEntry::GT;
684     if (Direction & Dependence::DVEntry::GT)
685       RevDirection |= Dependence::DVEntry::LT;
686     DV[Level - 1].Direction = RevDirection;
687     // Reverse the dependence distance as well.
688     if (DV[Level - 1].Distance != nullptr)
689       DV[Level - 1].Distance = SE->getNegativeSCEV(DV[Level - 1].Distance);
690   }
691 
692   LLVM_DEBUG(dbgs() << "After normalizing negative direction vectors:\n";
693              dump(dbgs()););
694   return true;
695 }
