757     break;
758   case SCEVMonotonicityType::Invariant:
759     OS << "Invariant\n";
760     break;
761   case SCEVMonotonicityType::MultivariateSignedMonotonic:
762     OS << "MultivariateSignedMonotonic\n";
763     break;
