224 ///
225 ///   F(i_1, i_2, ..., i_N)
226 ///
227 /// For the domain of F, see the comment of SCEVMonotonicityDomain.
228 ///
229 /// A function F is said to be "monotonically increasing with respect to the
230 /// k-th loop" if x <= y implies the following condition:
231 ///
232 ///   F(i_1, ..., i_{k-1}, x, i_{k+1}, ..., i_N) <=
233 ///   F(i_1, ..., i_{k-1}, y, i_{k+1}, ..., i_N)
234 ///
235 /// where i_1, ..., i_{k-1}, i_{k+1}, ..., i_N, x, and y are elements of their
236 /// respective domains.
237 ///
238 /// Likewise F is "monotonically decreasing with respect to the k-th loop"
239 /// if x <= y implies
240 ///
241 ///   F(i_1, ..., i_{k-1}, x, i_{k+1}, ..., i_N) >=
242 ///   F(i_1, ..., i_{k-1}, y, i_{k+1}, ..., i_N)
243 ///
244 /// A function F that is monotonically increasing or decreasing with respect to
245 /// the k-th loop is simply called "monotonic with respect to k-th loop".
246 ///
247 /// A function F is said to be "multivariate monotonic" when it is monotonic
248 /// with respect to all of the N loops.
249 ///
250 /// Since integer comparison can be either signed or unsigned, we need to
251 /// distinguish monotonicity in the signed sense from that in the unsigned
252 /// sense. Note that the inequality "x <= y" merely indicates loop progression
253 /// and is not affected by the difference between signed and unsigned order.
254 ///
255 /// Currently we only consider monotonicity in a signed sense.
256 enum class SCEVMonotonicityType {
257   /// We don't know anything about the monotonicity of the SCEV.
258   Unknown,
259 
260   /// The SCEV is loop-invariant with respect to the outermost loop. In other
261   /// words, the function F corresponding to the SCEV is a constant function.
262   Invariant,
263 
264   /// The function F corresponding to the SCEV is multivariate monotonic in a
265   /// signed sense. Note that the multivariate monotonic function may also be a
266   /// constant function. The order employed in the definition of monotonicity
267   /// is not strict order.
268   MultivariateSignedMonotonic,
269 };
