419 /// A wrapper class for std::optional<APInt> that provides arithmetic operators
420 /// with overflow checking in a signed sense. This allows us to omit inserting
421 /// an overflow check at every arithmetic operation, which simplifies the code
422 /// if the operations are chained like `a + b + c + ...`.
423 ///
424 /// If an calculation overflows, the result becomes "invalid" which is
425 /// internally represented by std::nullopt. If any operand of an arithmetic
426 /// operation is "invalid", the result will also be "invalid".
427 struct OverflowSafeSignedAPInt {
428   OverflowSafeSignedAPInt() : Value(std::nullopt) {}
429   OverflowSafeSignedAPInt(const APInt &V) : Value(V) {}
430   OverflowSafeSignedAPInt(const std::optional<APInt> &V) : Value(V) {}
431 
432   OverflowSafeSignedAPInt operator+(const OverflowSafeSignedAPInt &RHS) const {
433     if (!Value || !RHS.Value)
434       return OverflowSafeSignedAPInt();
435     bool Overflow;
436     APInt Result = Value->sadd_ov(*RHS.Value, Overflow);
437     if (Overflow)
438       return OverflowSafeSignedAPInt();
439     return OverflowSafeSignedAPInt(Result);
440   }
441 
442   OverflowSafeSignedAPInt operator+(int RHS) const {
443     if (!Value)
444       return OverflowSafeSignedAPInt();
445     return *this + fromInt(RHS);
446   }
447 
448   OverflowSafeSignedAPInt operator-(const OverflowSafeSignedAPInt &RHS) const {
449     if (!Value || !RHS.Value)
450       return OverflowSafeSignedAPInt();
451     bool Overflow;
452     APInt Result = Value->ssub_ov(*RHS.Value, Overflow);
453     if (Overflow)
454       return OverflowSafeSignedAPInt();
455     return OverflowSafeSignedAPInt(Result);
456   }
457 
458   OverflowSafeSignedAPInt operator-(int RHS) const {
459     if (!Value)
460       return OverflowSafeSignedAPInt();
461     return *this - fromInt(RHS);
462   }
463 
464   OverflowSafeSignedAPInt operator*(const OverflowSafeSignedAPInt &RHS) const {
465     if (!Value || !RHS.Value)
466       return OverflowSafeSignedAPInt();
467     bool Overflow;
468     APInt Result = Value->smul_ov(*RHS.Value, Overflow);
469     if (Overflow)
470       return OverflowSafeSignedAPInt();
471     return OverflowSafeSignedAPInt(Result);
472   }
